import BotonTema from "../reutilizables/botonTema";
import Header2 from "../reutilizables/header2";
import Footer from "../reutilizables/footer";
import Github from "../reutilizables/github";

function cambiarContraseña() {
  return (
    <div>
      <BotonTema />
      <div id="container">
        <header id="header1">
          <button id="volver" onclick="window.history.back()">
            Volver
          </button>
        </header>
        <Header2 />
      </div>
    </div>
  );
}

export default cambiarContraseña;
